/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // The problem describes a multi-source shortest path problem on a grid,
    // where the "cost" is the time taken, and the priority is the maximum color.
    // This is best solved using a variation of Dijkstra's algorithm or a 0-1 BFS,
    // but since all edge weights (time to diffuse) are 1, a multi-source BFS is appropriate.

    // We need to track the time it takes for each color to reach each cell,
    // and the color that reached it first/with the max color.

    // Initialize the grid state: [time, color]
    // Infinity for time means unvisited/uncolored.
    const INF = Infinity;
    const grid = Array(n).fill(0).map(() => Array(m).fill(null).map(() => ({
        time: INF,
        color: 0
    })));

    // Priority Queue (Min-Heap based on time)
    // Stores elements: [time, color, row, col]
    // We use a custom structure/array to simulate a priority queue if a standard library one isn't available easily.
    // For simplicity and adherence to constraints (N*M <= 10^5), a standard BFS queue might suffice if we handle the max color rule carefully.
    // Since time increases by 1, a standard BFS queue (FIFO) works for finding the minimum time first.

    // Queue for BFS: [row, col, time, color]
    const queue = [];

    // 1. Initialize sources
    for (const [r, c, color] of sources) {
        grid[r][c] = { time: 0, color: color };
        queue.push([r, c, 0, color]);
    }

    // Directions: Up, Down, Left, Right
    const directions = [
        [-1, 0], [1, 0], [0, -1], [0, 1]
    ];

    let head = 0;
    while (head < queue.length) {
        const [r, c, time, color] = queue[head++];

        const nextTime = time + 1;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const neighbor = grid[nr][nc];

                // The rule: If multiple colors arrive at the same time step, the one with the max color wins.
                // If a cell is unvisited (time === INF), the current path is the first arrival.
                if (neighbor.time === INF) {
                    // First arrival: update and enqueue
                    grid[nr][nc] = { time: nextTime, color: color };
                    queue.push([nr, nc, nextTime, color]);
                } else if (nextTime === neighbor.time) {
                    // Simultaneous arrival: take max color
                    if (color > neighbor.color) {
                        // Update color, but we must re-enqueue to propagate this new higher color
                        // This turns the pure BFS into a relaxation process similar to Dijkstra's when colors are updated.
                        // Since time hasn't changed, this might cause infinite loops if not careful.

                        // Re-evaluation: The problem states: "If multiple colors... arrive at the same time step, that unit cell will adopt the color with the maximum value."
                        // This implies that once a cell is colored, its final color and arrival time are set based on the *earliest* time it can be reached.
                        // If a higher color reaches it *at the same earliest time*, the color updates.

                        // If we strictly follow BFS (time-ordered), when we process (r, c) at time T, we are propagating T+1.
                        // If neighbor.time is already set to T+1, we check the color.
                        if (color > neighbor.color) {
                            grid[nr][nc].color = color;
                            // Re-enqueueing is necessary because this color change might affect its neighbors' future updates,
                            // even if the arrival time remains the same.
                            queue.push([nr, nc, nextTime, color]); 
                        }
                    }
                } else if (nextTime < neighbor.time) {
                    // Shorter path found (shouldn't happen in standard BFS if graph is unweighted, but possible if the initial sources weren't perfectly time-sorted, though here time only increases by 1)
                    // Since we start from time 0 and only increment, if neighbor.time is finite, nextTime >= neighbor.time unless we found a bug in logic.
                    // For robustness against complex propagation, we check:
                    grid[nr][nc] = { time: nextTime, color: color };
                    queue.push([nr, nc, nextTime, color]);
                }
                // If nextTime > neighbor.time, we ignore it (already reached faster).
            }
        }
    }

    // 3. Format the output
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            result[r][c] = grid[r][c].color;
        }
    }

    return result;
}

