import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.Deque;
import java.util.List;

public class Solution {
    // Helper class to store cell state
    private static class Cell {
        int time;
        int color;

        Cell(int time, int color) {
            this.time = time;
            this.color = color;
        }
    }

    // Helper class for BFS queue elements
    private static class QueueNode {
        int r, c;
        int time;
        int color;

        QueueNode(int r, int c, int time, int color) {
            this.r = r;
            this.c = c;
            this.time = time;
            this.color = color;
        }
    }

    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // Initialize the grid state: [time, color]
        // Use Integer.MAX_VALUE as infinity for time
        Cell[][] grid = new Cell[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                grid[i][j] = new Cell(Integer.MAX_VALUE, 0);
            }
        }

        // Queue for BFS: stores [r, c, time, color]
        Deque<QueueNode> queue = new ArrayDeque<>();

        // 1. Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            grid[r][c] = new Cell(0, color);
            queue.add(new QueueNode(r, c, 0, color));
        }

        // Directions: Up, Down, Left, Right
        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        // Multi-source BFS/Relaxation
        while (!queue.isEmpty()) {
            QueueNode current = queue.poll();
            int r = current.r;
            int c = current.c;
            int time = current.time;
            int color = current.color;

            int nextTime = time + 1;

            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                // Check boundaries
                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    Cell neighbor = grid[nr][nc];

                    // Case 1: Unvisited cell
                    if (neighbor.time == Integer.MAX_VALUE) {
                        // First arrival: update and enqueue
                        grid[nr][nc] = new Cell(nextTime, color);
                        queue.add(new QueueNode(nr, nc, nextTime, color));
                    } 
                    // Case 2: Simultaneous arrival at the current best time for the neighbor
                    else if (nextTime == neighbor.time) {
                        // Simultaneous arrival: take max color
                        if (color > neighbor.color) {
                            // Update color. Re-enqueue because this higher color might propagate changes.
                            neighbor.color = color;
                            queue.add(new QueueNode(nr, nc, nextTime, color));
                        }
                    } 
                    // Case 3: Shorter path found (Should not happen in this specific BFS structure since time only increases by 1)
                    else if (nextTime < neighbor.time) {
                        // This handles relaxation if we found a strictly faster path.
                        grid[nr][nc] = new Cell(nextTime, color);
                        queue.add(new QueueNode(nr, nc, nextTime, color));
                    }
                    // If nextTime > neighbor.time, we ignore it (already reached faster).
                }
            }
        }

        // 3. Format the output
        long[][] result = new long[N][M];
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < M; c++) {
                result[r][c] = grid[r][c].color;
            }
        }

        return result;
    }
}
