import java.util.Arrays;
import java.util.LinkedList;
import java.util.Queue;

class CellState {
    int time;
    int color;

    public CellState(int time, int color) {
        this.time = time;
        this.color = color;
    }
}

// Helper class for the queue elements
class QueueElement {
    int r;
    int c;
    int time;
    int color;

    public QueueElement(int r, int c, int time, int color) {
        this.r = r;
        this.c = c;
        this.time = time;
        this.color = color;
    }
}

public class Solution {
    /**
     * @param n The number of rows.
     * @param m The number of columns.
     * @param sources The initial sources array.
     * @return The final grid state.
     */
    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // Grid to store the state: [time, color]
        CellState[][] grid = new CellState[N][M];

        // Initialize grid: time = Integer.MAX_VALUE (Infinity), color = 0
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                grid[i][j] = new CellState(Integer.MAX_VALUE, 0);
            }
        }

        // Queue for BFS: stores [r, c, time, color]
        Queue<QueueElement> queue = new LinkedList<>();

        // 1. Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            grid[r][c] = new CellState(0, color);
            queue.offer(new QueueElement(r, c, 0, color));
        }

        // Directions: Up, Down, Left, Right
        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        // BFS Simulation
        while (!queue.isEmpty()) {
            QueueElement current = queue.poll();
            int r = current.r;
            int c = current.c;
            int time = current.time;
            int color = current.color;

            int nextTime = time + 1;

            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                // Check boundaries
                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    CellState neighbor = grid[nr][nc];

                    // Case 1: Unvisited cell (time == INF)
                    if (neighbor.time == Integer.MAX_VALUE) {
                        // First arrival: update and enqueue
                        grid[nr][nc].time = nextTime;
                        grid[nr][nc].color = color;
                        queue.offer(new QueueElement(nr, nc, nextTime, color));
                    } 
                    // Case 2: Simultaneous arrival (nextTime == neighbor.time)
                    else if (nextTime == neighbor.time) {
                        // Simultaneous arrival: take max color
                        if (color > neighbor.color) {
                            // Update color
                            grid[nr][nc].color = color;
                            // Re-enqueue is crucial to propagate the higher color to neighbors, 
                            // even if the arrival time remains the same.
                            queue.offer(new QueueElement(nr, nc, nextTime, color));
                        }
                    }
                    // Case 3: Faster arrival already occurred (nextTime > neighbor.time)
                    // Ignored.

                    // Case 4: Faster arrival occurred, but current path might offer a higher color at the same time.
                    // This is already handled in Case 2 if neighbor.time == nextTime.
                    // If neighbor.time < nextTime, we ignore it as it arrived earlier.
                }
            }
        }

        // 3. Format the output
        long[][] result = new long[N][M];
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < M; c++) {
                result[r][c] = grid[r][c].color;
            }
        }

        return result;
    }
}
