        // We use an array where index 0 is time, index 1 is color.
        // Initialize with time = infinity, color = 0.
        int[][] grid = new int[N][M];
        for (int i = 0; i < N; i++) {
            Arrays.fill(grid[i], Integer.MAX_VALUE);
        }

        // Priority Queue for Dijkstra-like approach: prioritize minimum time.
        // If times are equal, prioritize maximum color.
        Queue<CellState> pq = new LinkedList<>();

        // 1. Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            // Sources are at time 0
            if (grid[r][c] > 0 || (grid[r][c] == 0 && color > grid[r][c])) {
                 // For sources, the time is 0, color is given. We handle the initial state carefully.
                 grid[r][c] = color;
                 pq.add(new CellState(r, c, 0, color));
            }
        }

        // Re-initializing grid to properly track time vs color
        // Since N*M is small (<= 10^5), we can use a structure that holds both time and color.
        class State {
            int time;
            int color;
            int r, c;

            State(int time, int color, int r, int c) {
                this.time = time;
                this.color = color;
                this.r = r;
                this.c = c;
            }
        }

        // Redo initialization using a proper structure for Dijkstra/BFS relaxation
        // StateGrid[r][c] = {min_time, max_color_at_that_time}
        int[][] minTime = new int[N][M];
        int[][] finalColor = new int[N][M];
        for (int i = 0; i < N; i++) {
            Arrays.fill(minTime[i], Integer.MAX_VALUE);
            Arrays.fill(finalColor[i], 0);
        }

        // Priority Queue: Min-heap based on time, then Max-heap based on color (tie-breaker)
        // Comparator: (a, b) -> compare times first. If times equal, compare colors descending (b.color - a.color).
        java.util.PriorityQueue<State> pqDijkstra = new java.util.PriorityQueue<>(
            Comparator.comparingInt((State s) -> s.time)
                      .thenComparingInt(s -> -s.color) // Smaller value means higher priority (larger color)
