                    if (color > neighbor.color) {
                        // Update color, but we must re-enqueue to propagate this new higher color
                        // This turns the pure BFS into a relaxation process similar to Dijkstra's when colors are updated.
                        // Since time hasn't changed, this might cause infinite loops if not careful.

