import java.util.LinkedList;
import java.util.Queue;
import java.util.Arrays;

class CellState {
    int time;
    int color;

    public CellState(int time, int color) {
        this.time = time;
        this.color = color;
    }
}

// Helper class to manage the queue elements for BFS
class QueueItem {
    int r;
    int c;
    int time;
    int color;

    public QueueItem(int r, int c, int time, int color) {
        this.r = r;
        this.c = c;
        this.time = time;
        this.color = color;
    }
}

public class Solution {
    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // grid stores the final state: {time, color}
        // Use a large number for infinity time. Since N*M <= 10^5, N*M is a safe upper bound for time.
        final int INF = N * M + 1;
        CellState[][] grid = new CellState[N][M];

        // Initialize grid
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                grid[i][j] = new CellState(INF, 0);
            }
        }

        // BFS Queue: stores [r, c, time, color]
        Queue<QueueItem> queue = new LinkedList<>();

        // 1. Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            if (grid[r][c].time > 0) {
                // Should not happen based on constraints (unique sources), but good practice
                if (color > grid[r][c].color) {
                    grid[r][c].color = color;
                    grid[r][c].time = 0;
                    queue.add(new QueueItem(r, c, 0, color));
                }
            } else {
                grid[r][c].time = 0;
                grid[r][c].color = color;
                queue.add(new QueueItem(r, c, 0, color));
            }
        }

        // Directions: Up, Down, Left, Right
        int[][] directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

        // 2. Multi-source BFS with relaxation for max color at same time
        while (!queue.isEmpty()) {
            QueueItem current = queue.poll();
            int r = current.r;
            int c = current.c;
            int time = current.time;
            int color = current.color;

            int nextTime = time + 1;

            for (int[] dir : directions) {
                int dr = dir[0];
                int dc = dir[1];
                int nr = r + dr;
                int nc = c + dc;

                // Check boundaries
                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    CellState neighbor = grid[nr][nc];

                    if (neighbor.time == INF) {
                        // Case 1: Unvisited cell. This is the first time it can be reached.
                        neighbor.time = nextTime;
                        neighbor.color = color;
                        // Enqueue to propagate
                        queue.add(new QueueItem(nr, nc, nextTime, color));
                    } else if (nextTime == neighbor.time) {
                        // Case 2: Simultaneous arrival (at the earliest known time). Update color if current is larger.
                        if (color > neighbor.color) {
                            neighbor.color = color;
                            // Since the color changed at the same earliest time, this new color needs to propagate.
                            // Re-enqueueing maintains the property that the cell propagates its final/best state.
                            queue.add(new QueueItem(nr, nc, nextTime, color));
                        }
                    }
                    // Case 3: nextTime > neighbor.time. Already reached faster, ignore.
                    // Case 4: nextTime < neighbor.time. Impossible in standard BFS setup where time only increases.
                }
            }
        }

        // 3. Format the output
        long[][] result = new long[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                result[i][j] = grid[i][j].color;
            }
        }

        return result;
    }
}
